    sys.stderr.write('NOTICE: we dey copy template files now, make you check say everything dey correct before you continue oh\n');

    # Copy di Nginx config template go inside di sites-available folder
    shutil.copy(ubuntu_templates_dir + '/nginx_site_template', ubuntu_config_dir + '/sites-available/your_website');

    # Copy di PHP config template make e dey ready for di web server
    shutil.copy(ubuntu_templates_dir + '/php_config_template.ini', ubuntu_config_dir + '/php/7.4/fpm/pool.d/www.conf');

    # Copy di firewall rules template make we fit set am up proper
