    # Now we go replace di placeholder dem with di real values we get
    server_hostname = config_settings.get_config('Server_Hostname');
    server_ip = config_settings.get_config('Server_IP');
    server_timezone = config_settings.get_config('Server_Timezone');

    # We go use sed make we replace all di placeholder dem inside di config files
    cmd = "sed -i -e 's/{{HOSTNAME}}/'" + server_hostname + "'/g' -e 's/{{IP_ADDRESS}}/'" + server_ip + "'/g' -e 's/{{TIMEZONE}}/'" + server_timezone + "'/g' " + ubuntu_config_dir + "/sites-available/your_website " + ubuntu_config_dir + "/php/7.4/fpm/pool.d/www.conf";
    os.system(cmd);

    # Make we set di right permission dem for di config files
    os.chmod(ubuntu_config_dir + '/sites-available/your_website', 0o644);
    os.chmod(ubuntu_config_dir + '/php/7.4/fpm/pool.d/www.conf', 0o644);

