  private function checkUserSessionValid($sessionToken)
  {
    $session_timeout = sfConfig::get('app_sf_guard_session_timeout', 1800);
    $current_time = time();

    $user_session = sfGuardUserSessionPeer::doFetchByToken($sessionToken);

    if (!$user_session || ($current_time - $user_session->getCreatedAt()) > $session_timeout) {
      return false;
    }

    $user = $user_session->getsfGuardUser();
    return $user && $user->getIsActive();
  }

