// Safely grab da username and password from da form, make sure dem clean
    $username = isset($_POST['username']) ? trim($_POST['username']) : '';
    $password = isset($_POST['password']) ? trim($_POST['password']) : '';

    // Check if dem fields empty, if yes, tell da user straight
    if (empty($username) || empty($password)) {
        die(json_encode(['success' => false, 'message' => 'Username and password must fill out proper.']));
    }

    // Prepare da query safe, no direct input goin' in
    $sql = "SELECT user_id, user_name, password_hash, last_login, permissions, salt FROM " . $ecs->table('users') . " WHERE user_name = ?";
    $stmt = $db->prepare($sql);

    // Bind da username proper, den execute
    $stmt->bind_param("s", $username);
    $stmt->execute();
    $result = $stmt->get_result();

    // If we find da user, check da password with da salt
    if ($user = $result->fetch_assoc()) {
        $stored_hash = $user['password_hash'];
        $salt = $user['salt'];

        // Hash da input password with da salt and compare
        $input_hash = hash('sha256', $password . $salt);
        if ($input_hash === $stored_hash) {
            // Password match, start da session safe
            session_start();
            $_SESSION['user_id'] = $user['user_id'];
            $_SESSION['user_name'] = $user['user_name'];
            $_SESSION['permissions'] = $user['permissions'];

            // Update last login time
            $update_sql = "UPDATE " . $ecs->table('users') . " SET last_login = NOW() WHERE user_id = ?";
            $update_stmt = $db->prepare($update_sql);
            $update_stmt->bind_param("i", $user['user_id']);
            $update_stmt->execute();

            die(json_encode(['success' => true, 'message' => 'Login successful, welcome back!']));
        }
    }

    // If we reach here, login fail
    die(json_encode(['success' => false, 'message' => 'Invalid username or password. Try again.']));

